# Trigger annotation migration: 2026-06-06 JST
from pathlib import Path
import re

info_path = Path('site/information-and-relation.html')
image_path = Path('site/image-and-preimage-emotion.html')
css_path = Path('site/assets/style.css')

llm_note = '''      <aside class="note-box">
        <h3>注記｜LLMが圧縮しているもの</h3>
        <p>LLMを「意味を圧縮している」と言うと、直観的には分かりやすい。しかし、数学的・情報科学的には少し慎重に言い直した方がよい。LLMがそのまま意味を保存している、あるいは意味という実体を内部に持っている、と考えるとズレる。</p>
        <p>より安全には、LLMは、訓練データ中の統計的依存関係、文脈依存的なトークン分布、表現空間上のパターンをパラメータに圧縮している、と言える。</p>
        <p>ここでいう統計的依存関係とは、あるトークンや表現が、どのような文脈で、どのトークンや表現と一緒に現れやすいかという傾向である。たとえば、ある語の後にどの語が来やすいか、ある文体ではどの語彙が選ばれやすいか、ある質問形式にはどの種類の応答が続きやすいか、といった関係である。</p>
        <p>文脈依存的なトークン分布とは、同じトークンでも、前後の文脈によって次に来る候補の分布が変わるということである。「犬」という語は、動物の話、比喩、罵倒、漢字、慣用句など、文脈によって異なる関係の場に置かれる。LLMは、その都度、文脈に応じて次のトークンの確率分布を作る。</p>
        <p>表現空間上のパターンとは、トークンや文脈が高次元ベクトルとして表され、その空間内で似た使われ方、近い文脈、対応しやすい概念が、ある配置や方向として表現されることである。これは「語そのものの本質」がベクトルになっているというより、語やトークンが文脈内でどのような関係を持ちうるかを計算するための位置である。</p>
        <p>したがって、LLMは意味そのものを倉庫のように保存しているのではない。大量の言語使用を通じて現れた、トークン同士、語と文脈、文体と応答、質問と回答、概念と比喩の結びつきやすさを、重み、attention、MLP、層の変換として再利用できる形にしている。</p>
        <p>ただし、これは「意味がまったく関係ない」という意味でもない。人間の言語使用は意味を伴っている。その言語使用を大量に通過した結果として、LLMの内部には、意味そのものではなく、意味を生み出してきた使用の痕跡、関係傾向、統計的な偏りが残っている。</p>
        <p>このため、「LLMは意味を圧縮している」と言うより、「LLMは、意味を生み出してきた言語使用の統計的依存関係を、高次元ベクトル空間と重みの変換として圧縮している」と言う方が正確である。</p>
      </aside>
'''

info_note = '''      <aside class="note-box">
        <h3>注記｜情報理論とシャノン情報量</h3>
        <p>「情報量は関係においてしか量を持たない」という直観は鋭い。ただし、数学的な情報理論として読む場合、この表現は少し強すぎる。情報量は「関係」一般によって直接決まるのではなく、確率分布、候補空間、符号化規則、観測者が前提にしている不確定性との関係で定義される。</p>
        <p>情報理論の初歩では、情報とはまず「どの候補が実現したかによって、不確定性がどれだけ減ったか」として考える。たとえば、表と裏が同じ確率で出るコインを投げて、結果が表だったと分かれば、表か裏かという二つの候補の不確定性が一つに絞られる。このとき、結果を知ることには情報量がある。</p>
        <p>一方で、最初から必ず表が出ると分かっているコインなら、表が出たと聞いても不確定性はほとんど減らない。この場合、同じ「表」という結果でも、情報量はほぼない。つまり、情報量は結果そのものの中に物のように入っているのではなく、その結果がどの確率分布のもとでどれくらい予想外だったかによって決まる。</p>
        <p>シャノン情報量では、ある出来事 \(x\) が起きる確率を \(p(x)\) としたとき、その出来事がもたらす情報量を次のように定義する。</p>
        <div class="math-block">$$I(x)=-\log_2 p(x)$$</div>
        <p>対数の底を2にすると単位はビットになる。\(p(x)\) が大きい、つまり起きやすい出来事なら情報量は小さい。\(p(x)\) が小さい、つまり起きにくい出来事なら情報量は大きい。</p>
        <p>たとえば、確率 \(1/2\) の出来事が起きたときの情報量は \(-\log_2(1/2)=1\) ビットである。確率 \(1/4\) の出来事なら \(-\log_2(1/4)=2\) ビットになる。より多くの候補の中から、より起こりにくいものが実現したと分かるほど、不確定性の減少は大きくなる。</p>
        <p>また、確率分布全体の平均的な不確定性はエントロピーで表される。</p>
        <div class="math-block">$$H(X)=-\sum_x p(x)\log_2 p(x)$$</div>
        <p>これは、その確率分布から結果が一つ出るとき、平均してどれくらいの情報量が得られるかを表す。候補が均等に散らばっているほどエントロピーは大きくなり、特定の候補に偏っているほどエントロピーは小さくなる。</p>
        <p>したがって、ここでいう「関係」を数学的に安全に言い直すなら、それは確率分布、候補空間、条件付き確率、符号化規則、観測者の事前状態などを含む。情報量は、単独の対象に実体として宿るのではなく、どの確率モデルのもとでその対象がどれほど予想外か、またどれだけ候補を絞ったかによって定まる。</p>
        <p>この意味で、情報量はたしかに関係的である。ただし、それは「あらゆる関係がそのまま情報量を生む」という意味ではない。数学的には、情報量は確率分布に対して定義される量であり、対象、候補空間、確率モデル、観測者の不確定性との関係の中で初めて測れる量である。</p>
      </aside>
'''

projection_note = '''<aside class="note-box">
<h3>注記｜透視投影の定義域</h3>
<p>透視投影を \((x,y,z)\mapsto(x/z,y/z)\) と書くとき、これはすべての三次元点に対して定義される写像ではない。分母に \(z\) が入るため、\(z=0\) の点では定義できない。</p>
<p>ここでは、簡略化したピンホールカメラモデルを考え、\(z\neq0\) の領域に限っている。実際のカメラモデルとしては、通常、カメラの前方にある点だけを対象にするため、\(z>0\) の領域に制限して考える。</p>
<p>したがって、ここでの透視投影は、三次元空間全体 \(\mathbb{R}^3\) から二次元平面への写像というより、カメラの前方にある点の領域から画像平面への写像である。</p>
<p>この注意は小さく見えるが重要である。定義域を意識しないと、写像がどこで定義され、どこで破綻するのかが曖昧になる。線形写像では空間全体に作用することが多いが、透視投影では、カメラ位置、画像平面、奥行き方向、\(z=0\) の特異性が関わる。そのため、ここでも線形代数から写真・遠近法へ移るときの断絶が現れている。</p>
</aside>

'''

info = info_path.read_text(encoding='utf-8')
if '注記｜LLMが圧縮しているもの' not in info:
    marker = '      <p>という、関係の傾向が大量に圧縮されている。</p>\n'
    if marker not in info:
        raise SystemExit('LLM marker not found')
    info = info.replace(marker, marker + llm_note, 1)
if '注記｜情報理論とシャノン情報量' not in info:
    marker = '      <h2 id="info-quantity">7. 情報量は関係においてしか量を持たない</h2>\n'
    if marker not in info:
        raise SystemExit('info quantity marker not found')
    info = info.replace(marker, marker + info_note, 1)
info_path.write_text(info, encoding='utf-8')

image = image_path.read_text(encoding='utf-8')
if '注記｜透視投影の定義域' not in image:
    marker = '<h2 id="observation-map">8. 写真を観測写像として見る</h2>\n'
    if marker not in image:
        raise SystemExit('projection marker not found')
    image = image.replace(marker, projection_note + marker, 1)
image_path.write_text(image, encoding='utf-8')

css = css_path.read_text(encoding='utf-8')
css = re.sub(r'#gap::after,#llm-compression::after,#info-quantity::after\{.*?\}(?=#gap::after)', '', css)
css = re.sub(r'#gap::after\{.*?\}(?=#llm-compression::after)', '', css)
css = re.sub(r'#llm-compression::after\{.*?\}(?=#info-quantity::after)', '', css)
css = re.sub(r'#info-quantity::after\{.*?\}(?=\.page-nav)', '', css)
css_path.write_text(css, encoding='utf-8')
